# src/nodes/script_generator.py
import json
import re
from typing import Dict
from anthropic import Anthropic
from src.config.settings import settings
from src.schemas.state import ScriptState
from src.prompts.script_prompt import build_generation_prompt

client = Anthropic(api_key=settings.ANTHROPIC_API_KEY)

def script_generator(state: ScriptState) -> Dict:
    """Generate script draft using Claude API."""

    # Build prompt with optional retry feedback
    retry_feedback = state.get("review_feedback", "")
    prompt = build_generation_prompt(state, retry_feedback)

    # Call Claude API
    response = client.messages.create(
        model=settings.CLAUDE_MODEL,
        max_tokens=settings.LLM_MAX_TOKENS,
        temperature=settings.LLM_TEMPERATURE,
        messages=[{
            "role": "user",
            "content": prompt
        }]
    )

    raw_text = response.content[0].text

    # Attempt JSON parsing with fallback
    draft_script = parse_llm_response(raw_text)

    return {
        "draft_script": draft_script,
        "retry_count": state.get("retry_count", 0)
    }

def parse_llm_response(raw_text: str) -> Dict[str, str]:
    """Parse LLM response with multiple fallback strategies."""

    # Strategy 1: Direct JSON parse
    try:
        return json.loads(raw_text)
    except json.JSONDecodeError:
        pass

    # Strategy 2: Extract JSON block with regex
    json_pattern = r'```json\s*({[^`]+})\s*```'
    match = re.search(json_pattern, raw_text, re.DOTALL)
    if match:
        try:
            return json.loads(match.group(1))
        except json.JSONDecodeError:
            pass

    # Strategy 3: Find any JSON object
    json_object_pattern = r'{[^{}]*(?:{[^{}]*}[^{}]*)*}'
    match = re.search(json_object_pattern, raw_text, re.DOTALL)
    if match:
        try:
            return json.loads(match.group(0))
        except json.JSONDecodeError:
            pass

    # Fallback: Return raw text as single 'hook' section
    return {
        "hook": raw_text[:260],  # Truncate to max length
        "etymology": "",
        "context": "",
        "memory_anchor": "",
        "closing": ""
    }
