import pytest
from src.nodes.input_validator import input_validator

def test_valid_input():
    state = {
        "word": "test",
        "korean_meaning": "테스트",
        "etymology_explanation": "A" * 30
    }
    result = input_validator(state)
    assert result["retry_count"] == 0
    assert "word" in result

def test_missing_field():
    with pytest.raises(ValueError):
        input_validator({"word": "test"})

# tests/integration/test_graph_e2e.py
import json
import pytest
from src.graph import graph

@pytest.fixture
def sample_words():
    with open("tests/fixtures/sample_words.json") as f:
        return json.load(f)

def test_e2e_success(sample_words):
    for word_data in sample_words:
        result = graph.invoke(word_data)
        assert "full_script" in result
        assert result["estimated_duration_sec"] >= 45
        assert result["estimated_duration_sec"] <= 70  # Allow slight variance

def test_e2e_quality_metrics(sample_words):
    results = [graph.invoke(word) for word in sample_words]
    passed_count = sum(1 for r in results if r["quality_passed"])

    # PRD requirement: ≥90% quality pass rate
    pass_rate = passed_count / len(results)
    assert pass_rate >= 0.9, f"Quality pass rate {pass_rate:.1%} below 90% threshold"
